noncompliant:
[Serializable]
public class BankAccount : ISerializable
{
    private decimal balance;

    [SecurityPermission(SecurityAction.Demand, Flags = SecurityPermissionFlag.UnmanagedCode)]
    public BankAccount(decimal initialBalance) => balance = initialBalance;

    // Unsecured serialization constructor
    protected BankAccount(SerializationInfo info, StreamingContext context)
    {
        balance = info.GetDecimal("balance");
    }
}

[Serializable]
public class UserAccount : ISerializable
{
    private string username;
    private bool isAdmin;

    [SecurityPermission(SecurityAction.LinkDemand)]
    public UserAccount(string user) => username = user;

    // Missing security attribute on serialization constructor
    protected UserAccount(SerializationInfo info, StreamingContext context)
    {
        username = info.GetString("username");
        isAdmin = info.GetBoolean("isAdmin");
    }
}

compliant:
[Serializable]
public class BankAccount : ISerializable
{
    private decimal balance;

    [SecurityPermission(SecurityAction.Demand, Flags = SecurityPermissionFlag.UnmanagedCode)]
    public BankAccount(decimal initialBalance) => balance = initialBalance;

    // Properly secured serialization constructor
    [SecurityPermission(SecurityAction.Demand, Flags = SecurityPermissionFlag.UnmanagedCode)]
    protected BankAccount(SerializationInfo info, StreamingContext context)
    {
        balance = info.GetDecimal("balance");
    }
}

[Serializable]
public class UserAccount : ISerializable
{
    private string username;
    private bool isAdmin;

    [SecurityPermission(SecurityAction.LinkDemand)]
    public UserAccount(string user) => username = user;

    // Security attribute applied consistently
    [SecurityPermission(SecurityAction.LinkDemand)]
    protected UserAccount(SerializationInfo info, StreamingContext context)
    {
        username = info.GetString("username");
        isAdmin = info.GetBoolean("isAdmin");
    }
}

